import path from "node:path";
import fs from "fs-extra";
import { getVemDir } from "./fs.js";
import { getGitLastCommitForPath } from "./git.js";
export class ScalableLogService {
    subDir;
    constructor(subDir) {
        this.subDir = subDir;
    }
    async getBaseDir() {
        const vemDir = await getVemDir();
        const dir = path.join(vemDir, this.subDir);
        await fs.ensureDir(dir);
        return dir;
    }
    async addEntry(title, content, options) {
        const baseDir = await this.getBaseDir();
        const timestamp = new Date().toISOString();
        const id = `${timestamp.replace(/[:.]/g, "-")}-${title.toLowerCase().replace(/[^a-z0-9]/g, "-")}`;
        const filePath = path.join(baseDir, `${id}.md`);
        const commitLine = options?.commitHash
            ? `**Commit:** ${options.commitHash}\n\n`
            : "";
        const fullContent = `# ${title}\n\n**Date:** ${timestamp}\n\n${commitLine}${content}\n`;
        await fs.writeFile(filePath, fullContent, "utf-8");
        return id;
    }
    async getAllEntries() {
        const baseDir = await this.getBaseDir();
        const files = await fs.readdir(baseDir);
        const entries = [];
        for (const file of files) {
            if (file.endsWith(".md")) {
                const content = await fs.readFile(path.join(baseDir, file), "utf-8");
                const id = path.parse(file).name;
                // Simple parsing for title (first # header)
                const titleMatch = content.match(/^#\s+(.*)/);
                const title = titleMatch ? titleMatch[1] : id;
                entries.push({
                    id,
                    title,
                    content,
                    created_at: id
                        .substring(0, 19)
                        .replace(/-/g, (_m, offset) => offset === 10 ? "T" : offset === 13 || offset === 16 ? ":" : "-"),
                    file_path: path.join(baseDir, file),
                });
            }
        }
        // Sort by ID (which starts with timestamp)
        return entries.sort((a, b) => b.id.localeCompare(a.id));
    }
    async getMonolithicContent() {
        return this.getMonolithicContentWithOptions();
    }
    async getMonolithicContentWithOptions(options) {
        const entries = await this.getAllEntries();
        // reverse back to chronological for monolithic view
        const normalized = await Promise.all(entries.reverse().map(async (entry) => {
            if (!options?.includeCommitHashes)
                return entry.content;
            if (/^\*\*Commit:\*\*/m.test(entry.content))
                return entry.content;
            if (!entry.file_path)
                return entry.content;
            const commitHash = await getGitLastCommitForPath(entry.file_path);
            if (!commitHash)
                return entry.content;
            const dateMatch = entry.content.match(/^\*\*Date:\*\*.*$/m);
            if (!dateMatch) {
                return `**Commit:** ${commitHash}\n\n${entry.content}`;
            }
            return entry.content.replace(dateMatch[0], `${dateMatch[0]}\n\n**Commit:** ${commitHash}`);
        }));
        return normalized.join("\n---\n\n");
    }
    async archiveEntries(options) {
        const entries = await this.getAllEntries(); // Sorted by ID (date desc-ish)
        let toArchive = [];
        if (options.keepCount !== undefined) {
            toArchive = entries.slice(options.keepCount);
        }
        else if (options.olderThanDays !== undefined) {
            const now = new Date();
            const threshold = new Date(now.getTime() - options.olderThanDays * 24 * 60 * 60 * 1000);
            toArchive = entries.filter((e) => new Date(e.created_at) < threshold);
        }
        else {
            // If no options, default to keeping 20
            toArchive = entries.slice(20);
        }
        if (toArchive.length === 0)
            return 0;
        const baseDir = await this.getBaseDir();
        const archiveBase = path.join(baseDir, "archive");
        await fs.ensureDir(archiveBase);
        for (const entry of toArchive) {
            // Group by Year-Month
            const date = new Date(entry.created_at);
            const folder = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, "0")}`;
            const targetDir = path.join(archiveBase, folder);
            await fs.ensureDir(targetDir);
            const src = path.join(baseDir, `${entry.id}.md`);
            const dest = path.join(targetDir, `${entry.id}.md`);
            if (await fs.pathExists(src)) {
                await fs.move(src, dest, { overwrite: true });
            }
        }
        return toArchive.length;
    }
}
