import { createCipheriv, createDecipheriv, randomBytes, } from "node:crypto";
// ---------------------------------------------------------------------------
// AES-256-GCM encryption for org provider keys (BYOK storage)
// ---------------------------------------------------------------------------
// Requires PROVIDER_KEY_ENCRYPTION_SECRET env var: a 64-char hex string
// representing 32 random bytes.
//
// Generate with:  node -e "console.log(require('crypto').randomBytes(32).toString('hex'))"
// ---------------------------------------------------------------------------
const ALGORITHM = "aes-256-gcm";
const IV_BYTES = 12; // 96-bit IV recommended for GCM
const AUTH_TAG_BYTES = 16;
function getEncryptionKey() {
    const secret = process.env.PROVIDER_KEY_ENCRYPTION_SECRET;
    if (!secret || secret.length !== 64) {
        throw new Error("PROVIDER_KEY_ENCRYPTION_SECRET must be a 64-character hex string (32 bytes). " +
            "Generate one with: node -e \"console.log(require('crypto').randomBytes(32).toString('hex'))\"");
    }
    return Buffer.from(secret, "hex");
}
/**
 * Encrypt a provider API key for storage.
 * Returns a string in the format "iv:authTag:ciphertext" (all hex-encoded).
 */
export function encryptProviderKey(plaintext) {
    const key = getEncryptionKey();
    const iv = randomBytes(IV_BYTES);
    const cipher = createCipheriv(ALGORITHM, key, iv);
    const encrypted = Buffer.concat([
        cipher.update(plaintext, "utf8"),
        cipher.final(),
    ]);
    const authTag = cipher.getAuthTag();
    return [
        iv.toString("hex"),
        authTag.toString("hex"),
        encrypted.toString("hex"),
    ].join(":");
}
/**
 * Decrypt a provider API key retrieved from storage.
 * Expects the format produced by encryptProviderKey: "iv:authTag:ciphertext".
 */
export function decryptProviderKey(encoded) {
    const key = getEncryptionKey();
    const parts = encoded.split(":");
    if (parts.length !== 3) {
        throw new Error("Invalid encrypted key format.");
    }
    const [ivHex, authTagHex, ciphertextHex] = parts;
    const iv = Buffer.from(ivHex, "hex");
    const authTag = Buffer.from(authTagHex, "hex");
    const ciphertext = Buffer.from(ciphertextHex, "hex");
    if (iv.length !== IV_BYTES || authTag.length !== AUTH_TAG_BYTES) {
        throw new Error("Invalid encrypted key components.");
    }
    const decipher = createDecipheriv(ALGORITHM, key, iv);
    decipher.setAuthTag(authTag);
    return Buffer.concat([
        decipher.update(ciphertext),
        decipher.final(),
    ]).toString("utf8");
}
/**
 * Produce a display-safe preview of a provider key.
 * Shows the first 10 characters followed by "***".
 * Example: "sk-ant-api03-***"
 */
export function maskProviderKey(plaintext) {
    if (plaintext.length <= 10)
        return "***";
    return `${plaintext.slice(0, 10)}***`;
}
