import crypto from "node:crypto";
import dns from "node:dns";
/**
 * Returns true if the given IPv4 or IPv6 address falls within a private,
 * loopback, or link-local range that must be blocked to prevent SSRF.
 */
function isPrivateIp(ip) {
    // IPv6 loopback and ULA (fc00::/7 covers fc00:: – fdff::)
    if (ip.includes(":")) {
        const normalized = ip.toLowerCase();
        if (normalized === "::1")
            return true;
        if (/^fc[0-9a-f]{2}:/i.test(normalized))
            return true;
        if (/^fd[0-9a-f]{2}:/i.test(normalized))
            return true;
        if (/^fe80:/i.test(normalized))
            return true; // link-local
        return false;
    }
    // IPv4
    const parts = ip.split(".").map(Number);
    if (parts.length !== 4 || parts.some((p) => Number.isNaN(p)))
        return false;
    const [a, b, _c] = parts;
    return (a === 127 || // 127.0.0.0/8 loopback
        a === 10 || // 10.0.0.0/8 private
        (a === 172 && b >= 16 && b <= 31) || // 172.16.0.0/12 private
        (a === 192 && b === 168) || // 192.168.0.0/16 private
        (a === 169 && b === 254) || // 169.254.0.0/16 link-local / AWS metadata
        (a === 100 && b >= 64 && b <= 127) || // 100.64.0.0/10 CGNAT / Tailscale
        a === 0 // 0.0.0.0/8
    );
}
async function resolveAndValidateWebhookHostname(hostname) {
    const normalizedHost = hostname.toLowerCase().replace(/^\[|\]$/g, "");
    // Reject bare hostnames that are obviously local before DNS lookup.
    if (normalizedHost === "localhost" || normalizedHost === "0.0.0.0") {
        throw new Error("Webhook URLs must not target private or loopback addresses");
    }
    let resolvedAddresses;
    try {
        const result = await Promise.race([
            dns.promises.lookup(normalizedHost, { all: true, verbatim: false }),
            new Promise((_, reject) => setTimeout(() => reject(new Error("DNS lookup timed out")), 3000)),
        ]);
        resolvedAddresses = result;
    }
    catch (err) {
        throw new Error(`Webhook URL DNS lookup failed: ${err.message}`);
    }
    if (!Array.isArray(resolvedAddresses) || resolvedAddresses.length === 0) {
        throw new Error("Webhook URL DNS lookup failed: no addresses resolved");
    }
    const privateAddress = resolvedAddresses.find(({ address }) => isPrivateIp(address));
    if (privateAddress) {
        throw new Error(`Webhook URLs must not target private or loopback addresses (resolved to ${privateAddress.address})`);
    }
}
/**
 * Validate a webhook URL for SSRF safety.
 * Rejects non-https schemes and resolves the hostname via DNS to block
 * private/loopback IP addresses even when provided through a DNS alias.
 * Throws with a descriptive message if the URL is blocked.
 */
export async function validateWebhookUrl(url) {
    let parsed;
    try {
        parsed = new URL(url);
    }
    catch {
        throw new Error("Invalid URL");
    }
    if (parsed.protocol !== "https:") {
        throw new Error("Webhook URLs must use https");
    }
    await resolveAndValidateWebhookHostname(parsed.hostname);
}
export class WebhookService {
    /**
     * Detect if a URL is a Slack webhook
     */
    isSlackUrl(url) {
        return url.includes("hooks.slack.com/services/");
    }
    /**
     * Detect if a URL is a Discord webhook
     */
    isDiscordUrl(url) {
        return (url.includes("discord.com/api/webhooks/") ||
            url.includes("discordapp.com/api/webhooks/"));
    }
    /**
     * Get a friendly title for the event
     */
    getEventTitle(event, data) {
        switch (event) {
            case "task.created":
                return `🆕 Task Created: ${data.title || "Unnamed Task"}`;
            case "task.started":
                return `🚀 Task Started: ${data.title || "Unnamed Task"}`;
            case "task.blocked":
                return `🛑 Task Blocked: ${data.title || "Unnamed Task"}`;
            case "task.completed":
                return `✅ Task Completed: ${data.title || "Unnamed Task"}`;
            case "task.deleted":
                return `🗑️ Task Deleted: ${data.title || "Unnamed Task"}`;
            case "snapshot.pushed":
                return "📦 New Memory Snapshot Pushed";
            case "snapshot.verified":
                return "🛡️ Memory Snapshot Verified";
            case "snapshot.failed":
                return "❌ Memory Snapshot Verification Failed";
            case "decision.added":
                return "🧠 New Architectural Decision Recorded";
            case "changelog.updated":
                return "📝 Project Changelog Updated";
            case "drift.detected":
                return "⚠️ Truth Drift Detected";
            case "project.linked":
                return "🔗 Project Linked to Repository";
            default:
                return `VEM Event: ${event}`;
        }
    }
    /**
     * Get theme color for the event
     */
    getEventColor(event) {
        switch (event) {
            case "task.created":
            case "task.started":
            case "project.linked":
                return 0x3b82f6; // Blue
            case "task.completed":
            case "snapshot.verified":
                return 0x10b981; // Emerald
            case "task.blocked":
            case "drift.detected":
                return 0xf59e0b; // Amber
            case "snapshot.failed":
            case "task.deleted":
                return 0xef4444; // Red
            case "snapshot.pushed":
            case "decision.added":
            case "changelog.updated":
                return 0x8b5cf6; // Purple
            default:
                return 0x6b7280; // Gray
        }
    }
    /**
     * Format payload for Slack Block Kit
     */
    formatSlackPayload(payload) {
        const title = this.getEventTitle(payload.event, payload.data);
        const fields = [
            {
                type: "mrkdwn",
                text: `*Organization:*\n${payload.org_id}`,
            },
        ];
        if (payload.project_name) {
            fields.push({
                type: "mrkdwn",
                text: `*Project:*\n${payload.project_name}`,
            });
        }
        // Add event-specific data
        if (payload.event.startsWith("task.")) {
            if (payload.data.task_id) {
                fields.push({
                    type: "mrkdwn",
                    text: `*Task ID:*\n${payload.data.task_id}`,
                });
            }
            if (payload.data.status) {
                fields.push({
                    type: "mrkdwn",
                    text: `*Status:*\n${payload.data.status}`,
                });
            }
        }
        const blocks = [
            {
                type: "header",
                text: {
                    type: "plain_text",
                    text: title,
                    emoji: true,
                },
            },
            {
                type: "section",
                fields,
            },
        ];
        // Add link button if available
        if (payload.data.url) {
            blocks.push({
                type: "actions",
                elements: [
                    {
                        type: "button",
                        text: {
                            type: "plain_text",
                            text: "View in VEM",
                            emoji: true,
                        },
                        url: payload.data.url,
                        style: payload.event === "snapshot.failed" ? "danger" : "primary",
                    },
                ],
            });
        }
        blocks.push({
            type: "context",
            elements: [
                {
                    type: "mrkdwn",
                    text: `VEM Webhook • ${new Date(payload.timestamp).toLocaleString()}`,
                },
            ],
        });
        return { blocks };
    }
    /**
     * Format payload for Discord Embeds
     */
    formatDiscordPayload(payload) {
        const title = this.getEventTitle(payload.event, payload.data);
        const color = this.getEventColor(payload.event);
        const fields = [];
        if (payload.project_name) {
            fields.push({
                name: "Project",
                value: payload.project_name,
                inline: true,
            });
        }
        // Add event-specific fields
        if (payload.event.startsWith("task.")) {
            if (payload.data.task_id) {
                fields.push({
                    name: "Task ID",
                    value: String(payload.data.task_id),
                    inline: true,
                });
            }
            if (payload.data.status) {
                fields.push({
                    name: "Status",
                    value: String(payload.data.status),
                    inline: true,
                });
            }
        }
        if (payload.event === "snapshot.pushed" ||
            payload.event === "snapshot.verified") {
            if (payload.data.git_hash) {
                fields.push({
                    name: "Git Hash",
                    value: `\`${String(payload.data.git_hash).slice(0, 7)}\``,
                    inline: true,
                });
            }
        }
        return {
            embeds: [
                {
                    title,
                    url: payload.data.url || undefined,
                    color,
                    fields,
                    footer: {
                        text: "VEM Webhook Notification",
                    },
                    timestamp: payload.timestamp,
                },
            ],
        };
    }
    /**
     * Generate HMAC SHA-256 signature for webhook payload
     */
    generateSignature(payload, secret) {
        const body = JSON.stringify(payload);
        const signature = crypto
            .createHmac("sha256", secret)
            .update(body)
            .digest("hex");
        return `sha256=${signature}`;
    }
    /**
     * Deliver a single webhook
     */
    async deliverWebhook(webhook, payload, _attempt = 1) {
        try {
            // Re-validate URL + DNS on every delivery attempt to mitigate rebinding.
            await validateWebhookUrl(webhook.url);
        }
        catch (urlErr) {
            return {
                webhook_id: webhook.id,
                success: false,
                error_message: urlErr.message,
            };
        }
        try {
            const isSlack = this.isSlackUrl(webhook.url);
            const isDiscord = this.isDiscordUrl(webhook.url);
            // Transform payload for Slack/Discord
            let body = payload;
            if (isSlack) {
                body = this.formatSlackPayload(payload);
            }
            else if (isDiscord) {
                body = this.formatDiscordPayload(payload);
            }
            const signature = this.generateSignature(payload, webhook.secret);
            const controller = new AbortController();
            const timeoutId = setTimeout(() => controller.abort(), 10000); // 10 second timeout
            const response = await fetch(webhook.url, {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    "X-Webhook-Signature": signature,
                    "X-Webhook-Event": payload.event,
                    "X-Webhook-Delivery": crypto.randomUUID(),
                    "User-Agent": "VEM-Webhooks/1.0",
                },
                body: JSON.stringify(body),
                signal: controller.signal,
                // Avoid following redirects to an unvalidated destination.
                redirect: "manual",
            });
            clearTimeout(timeoutId);
            return {
                webhook_id: webhook.id,
                success: response.ok,
                status_code: response.status,
                error_message: response.ok
                    ? undefined
                    : `HTTP ${response.status}: ${response.statusText}`,
            };
        }
        catch (error) {
            const errorMessage = error instanceof Error ? error.message : "Unknown error";
            return {
                webhook_id: webhook.id,
                success: false,
                error_message: errorMessage,
            };
        }
    }
    /**
     * Find and trigger all webhooks subscribed to an event
     * @param findWebhooks - Database query function to find matching webhooks
     * @param recordDelivery - Database insert function to record delivery
     * @param eventType - The event type
     * @param orgId - Organization ID
     * @param projectId - Project ID (null for org-level events)
     * @param data - Event-specific data
     */
    async triggerWebhooks(findWebhooks, recordDelivery, eventType, orgId, projectId, data, projectName) {
        // Find all enabled webhooks subscribed to this event
        const webhooks = await findWebhooks({
            orgId,
            projectId,
            eventType,
        });
        if (webhooks.length === 0) {
            return;
        }
        // Build webhook payload
        const payload = {
            event: eventType,
            timestamp: new Date().toISOString(),
            org_id: orgId,
            project_id: projectId,
            project_name: projectName,
            data,
        };
        // Deliver to all webhooks (don't await - fire and forget for now)
        const deliveryPromises = webhooks.map(async (webhook) => {
            const result = await this.deliverWebhook(webhook, payload, 1);
            // Record delivery in database
            await recordDelivery({
                webhookId: webhook.id,
                eventType,
                payload,
                statusCode: result.status_code,
                success: result.success,
                attempt: 1,
                errorMessage: result.error_message,
            });
        });
        // Don't block on deliveries - they happen in background
        Promise.all(deliveryPromises).catch((err) => {
            console.error("[webhook] Unhandled error in webhook delivery batch:", err);
        });
    }
}
