import crypto from "node:crypto";
import path from "node:path";
import fs from "fs-extra";
export class ShardedFileStorage {
    baseDir;
    objectsDirName;
    constructor(baseDir, objectsDirName = "objects") {
        this.baseDir = baseDir;
        this.objectsDirName = objectsDirName;
    }
    getObjectsDir() {
        return path.join(this.baseDir, this.objectsDirName);
    }
    getShard(id) {
        const hash = crypto.createHash("sha1").update(id).digest("hex");
        return hash.substring(0, 2);
    }
    getFilePath(id) {
        const shard = this.getShard(id);
        return path.join(this.getObjectsDir(), shard, `${id}.json`);
    }
    async save(record) {
        const filePath = this.getFilePath(record.id);
        await fs.ensureDir(path.dirname(filePath));
        await fs.writeJson(filePath, record, { spaces: 2 });
    }
    async load(id) {
        const filePath = this.getFilePath(id);
        if (!(await fs.pathExists(filePath))) {
            return null;
        }
        return fs.readJson(filePath);
    }
    async delete(id) {
        const filePath = this.getFilePath(id);
        if (await fs.pathExists(filePath)) {
            await fs.remove(filePath);
        }
    }
    async listIds() {
        const objectsDir = this.getObjectsDir();
        if (!(await fs.pathExists(objectsDir))) {
            return [];
        }
        const shards = await fs.readdir(objectsDir);
        const ids = [];
        for (const shard of shards) {
            const shardPath = path.join(objectsDir, shard);
            const stat = await fs.stat(shardPath);
            if (!stat.isDirectory())
                continue;
            const files = await fs.readdir(shardPath);
            for (const file of files) {
                if (file.endsWith(".json")) {
                    ids.push(path.parse(file).name);
                }
            }
        }
        return ids;
    }
    async loadAll() {
        const ids = await this.listIds();
        const result = [];
        for (const id of ids) {
            const record = await this.load(id);
            if (record) {
                result.push(record);
            }
        }
        return result;
    }
}
export class TaskIndex {
    indexPath;
    constructor(baseDir) {
        this.indexPath = path.join(baseDir, "index.json");
    }
    async load() {
        if (!(await fs.pathExists(this.indexPath))) {
            return [];
        }
        try {
            const data = await fs.readJson(this.indexPath);
            return data.entries || [];
        }
        catch {
            return [];
        }
    }
    async save(entries) {
        await fs.ensureDir(path.dirname(this.indexPath));
        await fs.writeJson(this.indexPath, { entries }, { spaces: 2 });
    }
    async updateEntry(entry) {
        const entries = await this.load();
        const index = entries.findIndex((e) => e.id === entry.id);
        if (index !== -1) {
            entries[index] = entry;
        }
        else {
            entries.push(entry);
        }
        await this.save(entries);
    }
    async removeEntry(id) {
        const entries = await this.load();
        const filtered = entries.filter((e) => e.id !== id);
        await this.save(filtered);
    }
}
