import path from "node:path";
import fs from "fs-extra";
import { ConfigService } from "./config.js";
import { CHANGELOG_DIR, CONTEXT_FILE, CURRENT_STATE_FILE, DECISIONS_DIR, getRepoRoot, getVemDir, TASKS_DIR, } from "./fs.js";
import { TaskService } from "./tasks.js";
export class DoctorService {
    configService = new ConfigService();
    taskService = new TaskService();
    async runAllChecks() {
        const results = [];
        // Authentication checks
        results.push(await this.checkApiKey());
        results.push(await this.checkDeviceId());
        // Project setup checks
        results.push(await this.checkProjectLinked());
        results.push(await this.checkVemDirectory());
        results.push(await this.checkRequiredFiles());
        // Git integration checks
        results.push(await this.checkGitRepository());
        // Data integrity checks
        results.push(await this.checkTaskIntegrity());
        return results;
    }
    async checkApiKey() {
        try {
            const apiKey = await this.configService.getApiKey();
            if (!apiKey) {
                return {
                    name: "API Key",
                    status: "fail",
                    message: "API key not configured",
                    fix: "Run: vem login",
                    autoFixable: false,
                };
            }
            return {
                name: "API Key",
                status: "pass",
                message: "API key configured",
            };
        }
        catch (error) {
            return {
                name: "API Key",
                status: "fail",
                message: `Error checking API key: ${error.message}`,
                autoFixable: false,
            };
        }
    }
    async checkDeviceId() {
        try {
            const deviceId = await this.configService.getDeviceId();
            if (!deviceId) {
                return {
                    name: "Device ID",
                    status: "warn",
                    message: "Device ID not registered (will be created on next operation)",
                    autoFixable: true,
                };
            }
            return {
                name: "Device ID",
                status: "pass",
                message: "Device ID registered",
            };
        }
        catch (error) {
            return {
                name: "Device ID",
                status: "fail",
                message: `Error checking device ID: ${error.message}`,
                autoFixable: false,
            };
        }
    }
    async checkProjectLinked() {
        try {
            const projectId = await this.configService.getProjectId();
            if (!projectId) {
                return {
                    name: "Project Link",
                    status: "fail",
                    message: "Project not linked to cloud",
                    fix: "Run: vem init",
                    autoFixable: false,
                };
            }
            return {
                name: "Project Link",
                status: "pass",
                message: `Project linked (${projectId})`,
            };
        }
        catch (error) {
            return {
                name: "Project Link",
                status: "fail",
                message: `Error checking project link: ${error.message}`,
                autoFixable: false,
            };
        }
    }
    async checkVemDirectory() {
        try {
            const vemDir = await getVemDir();
            const exists = await fs.pathExists(vemDir);
            if (!exists) {
                return {
                    name: ".vem Directory",
                    status: "fail",
                    message: ".vem/ directory does not exist",
                    fix: "Run: vem init",
                    autoFixable: true,
                };
            }
            // Check subdirectories
            const tasksDir = path.join(vemDir, TASKS_DIR);
            const decisionsDir = path.join(vemDir, DECISIONS_DIR);
            const changelogDir = path.join(vemDir, CHANGELOG_DIR);
            const tasksDirExists = await fs.pathExists(tasksDir);
            const decisionsDirExists = await fs.pathExists(decisionsDir);
            const changelogDirExists = await fs.pathExists(changelogDir);
            if (!tasksDirExists || !decisionsDirExists || !changelogDirExists) {
                return {
                    name: ".vem Directory",
                    status: "warn",
                    message: "Missing subdirectories in .vem/",
                    fix: "Run: vem init",
                    autoFixable: true,
                };
            }
            return {
                name: ".vem Directory",
                status: "pass",
                message: ".vem/ directory structure valid",
            };
        }
        catch (error) {
            return {
                name: ".vem Directory",
                status: "fail",
                message: `Error checking .vem directory: ${error.message}`,
                autoFixable: false,
            };
        }
    }
    async checkRequiredFiles() {
        try {
            const vemDir = await getVemDir();
            const contextPath = path.join(vemDir, CONTEXT_FILE);
            const currentStatePath = path.join(vemDir, CURRENT_STATE_FILE);
            const contextExists = await fs.pathExists(contextPath);
            const currentStateExists = await fs.pathExists(currentStatePath);
            if (!contextExists || !currentStateExists) {
                return {
                    name: "Required Files",
                    status: "warn",
                    message: "Missing CONTEXT.md or CURRENT_STATE.md",
                    fix: "Run: vem init",
                    autoFixable: true,
                };
            }
            return {
                name: "Required Files",
                status: "pass",
                message: "All required files present",
            };
        }
        catch (error) {
            return {
                name: "Required Files",
                status: "fail",
                message: `Error checking required files: ${error.message}`,
                autoFixable: false,
            };
        }
    }
    async checkGitRepository() {
        try {
            await getRepoRoot();
            return {
                name: "Git Repository",
                status: "pass",
                message: "Inside git repository",
            };
        }
        catch (_error) {
            return {
                name: "Git Repository",
                status: "fail",
                message: "Not inside a git repository",
                autoFixable: false,
            };
        }
    }
    async checkTaskIntegrity() {
        try {
            const tasks = await this.taskService.getTasks();
            // Check for duplicate IDs
            const ids = new Set();
            const duplicates = [];
            for (const task of tasks) {
                if (ids.has(task.id)) {
                    duplicates.push(task.id);
                }
                ids.add(task.id);
            }
            if (duplicates.length > 0) {
                return {
                    name: "Task Integrity",
                    status: "fail",
                    message: `Duplicate task IDs found: ${duplicates.join(", ")}`,
                    autoFixable: false,
                };
            }
            // Check for orphaned references
            const orphanedRefs = [];
            for (const task of tasks) {
                if (task.blocked_by) {
                    for (const blockerId of task.blocked_by) {
                        if (!ids.has(blockerId)) {
                            orphanedRefs.push(`${task.id} references ${blockerId}`);
                        }
                    }
                }
            }
            if (orphanedRefs.length > 0) {
                return {
                    name: "Task Integrity",
                    status: "warn",
                    message: `Orphaned task references: ${orphanedRefs[0]}`,
                    fix: `Run: vem task update ${orphanedRefs[0].split(" ")[0]} --blocked-by ""`,
                    autoFixable: false,
                };
            }
            return {
                name: "Task Integrity",
                status: "pass",
                message: `All ${tasks.length} tasks valid`,
            };
        }
        catch (error) {
            return {
                name: "Task Integrity",
                status: "fail",
                message: `Error checking task integrity: ${error.message}`,
                autoFixable: false,
            };
        }
    }
}
