import { createHash, timingSafeEqual } from "node:crypto";
/**
 * Compares a bearer token against a secret using constant-time comparison.
 * Both values are hashed to a fixed-length digest before comparison so that
 * the comparison time does not leak the secret's length.
 */
export function bearerSecretMatches(token, secret) {
    const expected = createHash("sha256").update(secret).digest();
    const actual = createHash("sha256").update(token).digest();
    return timingSafeEqual(actual, expected);
}
const SECRET_PATTERNS = [
    {
        name: "private_key",
        regex: /-----BEGIN (?:RSA|EC|DSA|OPENSSH|PGP) PRIVATE KEY-----/g,
        replace: "[REDACTED:private_key]",
    },
    {
        name: "aws_access_key",
        regex: /\bAKIA[0-9A-Z]{16}\b/g,
        replace: "[REDACTED:aws_access_key]",
    },
    {
        name: "aws_secret_key",
        regex: /\b(aws_secret_access_key)\b\s*[:=]\s*([A-Za-z0-9/+=]{40})/gi,
        replace: (_match, key) => `${key}=[REDACTED:aws_secret_key]`,
    },
    {
        name: "github_token",
        regex: /\bghp_[A-Za-z0-9]{36}\b/g,
        replace: "[REDACTED:github_token]",
    },
    {
        name: "github_pat",
        regex: /\bgithub_pat_[A-Za-z0-9_]{22,}\b/g,
        replace: "[REDACTED:github_pat]",
    },
    {
        name: "slack_token",
        regex: /\bxox[baprs]-[A-Za-z0-9-]{10,}\b/g,
        replace: "[REDACTED:slack_token]",
    },
];
export function redactSecrets(input) {
    if (!input)
        return input;
    let output = input;
    for (const pattern of SECRET_PATTERNS) {
        if (pattern.regex.test(output)) {
            if (typeof pattern.replace === "string") {
                output = output.replace(pattern.regex, pattern.replace);
            }
            else {
                output = output.replace(pattern.regex, pattern.replace);
            }
        }
        pattern.regex.lastIndex = 0;
    }
    return output;
}
export function detectSecrets(input) {
    if (!input)
        return [];
    const matches = new Set();
    for (const pattern of SECRET_PATTERNS) {
        if (pattern.regex.test(input)) {
            matches.add(pattern.name);
        }
        pattern.regex.lastIndex = 0;
    }
    return Array.from(matches);
}
