import { execSync } from "node:child_process";
import { getRepoRoot } from "./fs.js";
export async function getGitHeadHash() {
    try {
        const root = await getRepoRoot();
        const hash = execSync("git rev-parse HEAD", {
            cwd: root,
            stdio: ["ignore", "pipe", "ignore"],
        })
            .toString()
            .trim();
        return hash || null;
    }
    catch {
        return null;
    }
}
export async function getGitLastCommitForPath(filePath) {
    try {
        const root = await getRepoRoot();
        const relative = filePath.startsWith(root)
            ? filePath.slice(root.length + 1)
            : filePath;
        const hash = execSync(`git log -1 --format=%H -- "${relative.replace(/"/g, '\\"')}"`, {
            cwd: root,
            stdio: ["ignore", "pipe", "ignore"],
        })
            .toString()
            .trim();
        return hash || null;
    }
    catch {
        return null;
    }
}
