import { z } from "zod";
/**
 * Validates environment variables against a schema and exits the process if invalid.
 */
export function validateEnv(schema, serviceName) {
    try {
        return schema.parse(process.env);
    }
    catch (error) {
        if (error instanceof z.ZodError) {
            console.error(`\n❌ Invalid environment variables for ${serviceName}:`);
            for (const issue of error.issues) {
                console.error(`  - ${issue.path.join(".")}: ${issue.message}`);
            }
            console.error("\nPlease check your .env file or deployment configuration.\n");
            process.exit(1);
        }
        throw error;
    }
}
/**
 * Common environment variables used across multiple services.
 */
export const commonEnvSchema = {
    NODE_ENV: z
        .enum(["development", "production", "test"])
        .default("development"),
    INTERNAL_API_SECRET: z.string().min(1, "INTERNAL_API_SECRET is required"),
    DATABASE_URL: z.string().url("DATABASE_URL must be a valid URL"),
};
