/** Convert a CopilotSession / CopilotSessionDetail to the unified AgentSession shape. */
export function fromCopilotSession(s) {
    return {
        id: s.id,
        source: "copilot",
        summary: s.summary,
        branch: s.branch,
        repository: s.repository,
        git_root: s.git_root,
        cwd: s.cwd,
        created_at: s.created_at,
        updated_at: s.updated_at,
        intents: "intents" in s ? s.intents : [],
        user_messages: "user_messages" in s ? s.user_messages : [],
    };
}
/**
 * List agent sessions from all supported tools (Copilot, Claude, Gemini),
 * optionally filtered to the given git root, sorted newest-first.
 */
export async function listAllAgentSessions(gitRoot, sources = ["copilot", "claude", "gemini"]) {
    const [{ listCopilotSessions }, { listClaudeSessions }, { listGeminiSessions },] = await Promise.all([
        import("./copilot-sessions.js"),
        import("./claude-sessions.js"),
        import("./gemini-sessions.js"),
    ]);
    const results = await Promise.all([
        sources.includes("copilot")
            ? listCopilotSessions(gitRoot).then((ss) => ss.map(fromCopilotSession))
            : Promise.resolve([]),
        sources.includes("claude")
            ? listClaudeSessions(gitRoot)
            : Promise.resolve([]),
        sources.includes("gemini")
            ? listGeminiSessions(gitRoot)
            : Promise.resolve([]),
    ]);
    const all = results.flat();
    all.sort((a, b) => {
        if (!a.updated_at)
            return 1;
        if (!b.updated_at)
            return -1;
        return b.updated_at.localeCompare(a.updated_at);
    });
    return all;
}
/**
 * Compute statistics for a session from any supported agent tool.
 * Returns null if stats cannot be computed.
 */
export async function computeSessionStats(sessionId, source) {
    const { computeCopilotSessionStats } = await import("./copilot-sessions.js");
    const { computeClaudeSessionStats } = await import("./claude-sessions.js");
    const { computeGeminiSessionStats } = await import("./gemini-sessions.js");
    switch (source) {
        case "copilot":
            return computeCopilotSessionStats(sessionId);
        case "claude":
            return computeClaudeSessionStats(sessionId);
        case "gemini":
            return computeGeminiSessionStats(sessionId);
        default:
            return null;
    }
}
